import postcss from 'postcss';
import { compile } from './compiler';
export default function tailwindPostcss() {
  return {
    postcssPlugin: 'tailwindcss',
    Once(root: any) {
      compile(root);
    }
  };
}

import { parse } from './parser';
export function compile(root: any) {
  const config = parse(root);
  console.log('Compiling stylesheet with config:', config);
}

export function parse(root: any) {
  return {
    theme: { colors: { primary: '#4361EE' } }
  };
}

export { default as postcss } from './postcss';
export * from './compiler';
export * from './parser';
